#include <stdio.h>
int main() {
    // Implicit type casting examples
    int a = 10, b = 4;
    float result1 = a / b;  // Integer division, result truncated
    float result2 = (float)a / b;  // Explicit cast on a

    printf("Integer division: %d / %d = %d\n", a, b, a/b);
    printf("Implicit conversion: a/b as float = %f\n", result1);
    printf("Explicit casting: (float)a/b = %f\n", result2);

    // Explicit casting demonstration
    double pi = 3.14159;
    int intPi = (int)pi;  // Truncates decimal part
    printf("Double value: %f, After cast to int: %d\n", pi, intPi);

    // Character to integer promotion
    char ch = 'A';
    int val = ch + 1;  // Character promoted to int
    printf("Character 'A' + 1 as int: %d\n", val);

    return 0;
}

#include <stdio.h>

// Define enumerated type
enum days {MONDAY, TUESDAY, WEDNESDAY, THURSDAY, FRIDAY, SATURDAY, SUNDAY};

// Enum with custom values
enum months {JAN = 1, FEB = 2, MAR = 3, APR = 4, MAY = 5, JUN = 6,
             JUL = 7, AUG = 8, SEP = 9, OCT = 10, NOV = 11, DEC = 12};

int main() {
    enum days today = WEDNESDAY;
    enum months currentMonth = JUL;

    printf("Today is day number: %d\n", today);
    printf("Current month number: %d\n", currentMonth);

    // Using enum in switch
    switch(today) {
        case MONDAY: printf("Start of work week\n"); break;
        case FRIDAY: printf("End of work week\n"); break;
        case SATURDAY:
        case SUNDAY: printf("Weekend!\n"); break;
        default: printf("Midweek\n"); break;
    }

    return 0;
}

#include <stdio.h>

// Macro definition (no semicolon needed)
#define PI 3.14159
#define MAX_SIZE 100
#define MESSAGE "Hello, World!"

int main() {
    // const keyword usage
    const int MIN_AGE = 18;
    const float GRAVITY = 9.8;
    const char GRADE = 'A';

    printf("Constants using #define:\n");
    printf("PI = %f\n", PI);
    printf("MAX_SIZE = %d\n", MAX_SIZE);
    printf("MESSAGE = %s\n", MESSAGE);

    printf("\nConstants using const:\n");
    printf("MIN_AGE = %d\n", MIN_AGE);
    printf("GRAVITY = %f\n", GRAVITY);
    printf("GRADE = %c\n", GRADE);

    // Note: Attempting to modify would cause compile error
    // MIN_AGE = 21;  // Error: assignment of read-only variable

    return 0;
}
